class Solution:
    def shortestPath(self, grid, k: int) -> int:
        from collections import deque
        m, n = len(grid), len(grid[0])
        if m == 1 and n == 1:
            return 0
        # visited[r][c] = max eliminations remaining when we visited this cell
        visited = [[-1] * n for _ in range(m)]
        visited[0][0] = k
        q = deque([(0, 0, k, 0)])
        while q:
            r, c, elim, steps = q.popleft()
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n:
                    ne = elim - grid[nr][nc]
                    if ne >= 0 and ne > visited[nr][nc]:
                        if nr == m-1 and nc == n-1:
                            return steps + 1
                        visited[nr][nc] = ne
                        q.append((nr, nc, ne, steps + 1))
        return -1

